/// base. This value exposes when the floor candidate had to yield to the
/// precision-capped peak instead of silently relying on `min(floor, peak)`.
class AutoExploreZoomTargetRangeResolution {
  final double requestedPeakZoom;
  final double requestedFloorZoom;
  final AutoExploreZoomTargetRange range;

  const AutoExploreZoomTargetRangeResolution({
    required this.requestedPeakZoom,
    required this.requestedFloorZoom,
    required this.range,
  });

  factory AutoExploreZoomTargetRangeResolution.fromCandidates({
    required double peakZoom,
    required double floorZoom,
  }) {
    return AutoExploreZoomTargetRangeResolution(
      requestedPeakZoom: peakZoom,
      requestedFloorZoom: floorZoom,
      range: AutoExploreZoomTargetRange(
        peakZoom: peakZoom,
        floorZoom: min(floorZoom, peakZoom),
      ),
    );
  }

  bool get floorCappedByPeak => requestedFloorZoom > range.floorZoom;
}

/// Sanitized inputs used for one replayable auto-explore target decision.
///
/// This exposes the hidden fallback order used by the service: current zoom is
/// sanitized first, then a missing cycle base adopts that sanitized current
/// value. A malformed non-null cycle base is still sanitized independently.
class AutoExploreZoomPlanInputs {
  final double currentZoom;
  final double baseZoom;

  const AutoExploreZoomPlanInputs({
    required this.currentZoom,
    required this.baseZoom,
  });

  factory AutoExploreZoomPlanInputs.fromBounds({
    required AutoExploreZoomBounds bounds,
    required double currentZoom,
    required double? cycleBaseZoom,
  }) {
    final current = bounds.clamp(currentZoom);
    return AutoExploreZoomPlanInputs(
      currentZoom: current,
      baseZoom: bounds.clamp(cycleBaseZoom ?? current),
    );
  }
}

/// Replayable target-selection data for one auto-explore cycle step.
class AutoExploreZoomTargetPlan {
  final AutoExploreZoomPlanInputs inputs;
  final AutoExplorePeakZoomCandidates peakCandidates;
  final double peakZoom;
  final double floorZoom;
  final bool zoomingIn;

  const AutoExploreZoomTargetPlan({
    required this.inputs,
    required this.peakCandidates,
    required this.peakZoom,
    required this.floorZoom,
    required this.zoomingIn,
  }) : assert(floorZoom <= peakZoom, 'floorZoom must not exceed peakZoom');

  double get currentZoom => inputs.currentZoom;
  double get baseZoom => inputs.baseZoom;

  AutoExploreZoomTargetRange get targetRange =>
      AutoExploreZoomTargetRange.fromCandidates(
        peakZoom: peakZoom,
        floorZoom: floorZoom,
      );

  bool get isCollapsed => targetRange.isCollapsed;

  bool get respectsPrecisionHardMax => peakZoom <= peakCandidates.hardMaxZoom;

  double get targetZoom => targetRange.targetZoom(zoomingIn: zoomingIn);
}

/// Pure zoom-planning logic for [AutoExploreService].
///
/// Keeping target selection side-effect free makes the precision assumptions
/// replayable in tests without constructing timers or a renderer controller.
class AutoExploreZoomPlanner {
  final AutoExploreConfig config;
  final DeepZoomPrecisionPolicy precisionPolicy;

  const AutoExploreZoomPlanner({
    required this.config,
    this.precisionPolicy = const DeepZoomPrecisionPolicy(),
  });

  AutoExploreZoomBounds get _bounds => AutoExploreZoomBounds.fromConfig(config);
  AutoExploreCycleShape get _cycleShape =>
      AutoExploreCycleShape.fromConfig(config);

  double clampZoom(double zoom) => _bounds.clamp(zoom);

  double hardMaxZoomFor(String moduleId) {
    final headroom = AutoExplorePrecisionHeadroom.normalize(
      config.precisionHeadroom,
    );
    final safeThreshold = precisionPolicy.thresholdFor(moduleId) * headroom;
    return _bounds.clamp(safeThreshold);
  }

  AutoExplorePeakZoomCandidates peakZoomCandidates({
    required double baseZoom,
    required String moduleId,
  }) {
    final base = clampZoom(baseZoom);
    final hardMax = hardMaxZoomFor(moduleId);
    final cycleShape = _cycleShape;
    final maxSpanRatio = pow(10.0, cycleShape.maxLegSpanDecades).toDouble();

    return AutoExplorePeakZoomCandidates(
      baseZoom: base,
      minProgressZoom: clampZoom(base * 1.25),
      configuredPeakZoom: clampZoom(base * cycleShape.cycleMaxMultiplier),
      spanLimitedPeakZoom: clampZoom(base * maxSpanRatio),
      hardMaxZoom: hardMax,
    );
  }

  double computePeakZoom({
    required double baseZoom,
    required String moduleId,
  }) {
    return peakZoomCandidates(
      baseZoom: baseZoom,
      moduleId: moduleId,
    ).resolvedPeakZoom;
  }

  double computeFloorZoom(double baseZoom) {
    final bounds = _bounds;
    final base = bounds.clamp(baseZoom);
    final contextualFloor = base / _cycleShape.cycleMaxMultiplier;
    return bounds.clamp(max(bounds.minZoom, contextualFloor));
  }

  AutoExploreZoomPlanInputs planInputs({
    required double currentZoom,
    required double? cycleBaseZoom,
  }) {
    return AutoExploreZoomPlanInputs.fromBounds(
      bounds: _bounds,
      currentZoom: currentZoom,
      cycleBaseZoom: cycleBaseZoom,
    );
  }

  AutoExploreZoomTargetPlan planNextTarget({
    required double currentZoom,
    required double? cycleBaseZoom,
    required bool zoomingIn,
    required String moduleId,
  }) {
    final inputs = planInputs(
      currentZoom: currentZoom,
      cycleBaseZoom: cycleBaseZoom,
    );
    final peakCandidates = peakZoomCandidates(
      baseZoom: inputs.baseZoom,
      moduleId: moduleId,
    );
    final rangeResolution = AutoExploreZoomTargetRangeResolution.fromCandidates(
      peakZoom: peakCandidates.resolvedPeakZoom,
      floorZoom: computeFloorZoom(inputs.baseZoom),
    );

    return AutoExploreZoomTargetPlan(
      inputs: inputs,
      peakCandidates: peakCandidates,
      peakZoom: rangeResolution.range.peakZoom,
      floorZoom: rangeResolution.range.floorZoom,
      zoomingIn: zoomingIn,
    );
  }

  double nextTargetZoom({
    required double currentZoom,
    required double? cycleBaseZoom,
    required bool zoomingIn,
    required String moduleId,
  }) {
    return planNextTarget(
      currentZoom: currentZoom,
      cycleBaseZoom: cycleBaseZoom,
      zoomingIn: zoomingIn,
      moduleId: moduleId,
    ).targetZoom;
  }

  AutoExploreZoomAnimationPlan animationPlanForZoomLeg({
    required double startZoom,
    required double endZoom,
    required double speed,
  }) {
    final leg = AutoExploreZoomLeg.fromBounds(
      bounds: _bounds,
      startZoom: startZoom,
      endZoom: endZoom,
    );
    final effectiveSpeed = _effectiveSpeed(speed);

    final durationScale = AutoExploreDurationScale.normalize(
      config.maxDurationScale,
    );
    final normalized = AutoExploreZoomSpanScale.normalized(leg.spanDecades);
    final scale = 1.0 + normalized * (durationScale - 1.0);

    return AutoExploreZoomAnimationPlan(
      startZoom: leg.startZoom,
      endZoom: leg.endZoom,
      duration: Duration(
        milliseconds: AutoExploreLegDuration.milliseconds(
          baseDuration: config.travelDuration,
          scale: scale,
          speed: effectiveSpeed,
        ),
      ),
    );
  }

  Duration durationForZoomLeg({
    required double startZoom,
    required double endZoom,
    required double speed,
  }) {
    return animationPlanForZoomLeg(
      startZoom: startZoom,
      endZoom: endZoom,
      speed: speed,
    ).duration;
  }

  double _effectiveSpeed(double speed) => AutoExploreSpeed.normalize(speed);

  double interpolateZoom(double start, double end, double t) {
    final leg = AutoExploreZoomLeg.fromBounds(
      bounds: _bounds,
      startZoom: start,
      endZoom: end,
    );
    return leg.interpolate(t);
  }
}

import 'dart:async';
import 'package:flutter/animation.dart';
import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_runtime_state.dart';
import 'package:flutter_fractals/features/auto_explore/auto_explore_zoom_planner.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';

export 'auto_explore_zoom_planner.dart'
    show AutoExploreConfig, AutoExploreSpeed;

/// Auto navigation mode that performs zoom-only cinematic movement.
///
/// Behavior:
/// - Slowly zooms in from the current zoom to a smart module-aware peak.
/// - Then zooms back out to a smart floor.
/// - Repeats continuously.
///
/// Pan is never modified by this service, so the user can pan freely.
class AutoExploreService extends ChangeNotifier {
  static const Cubic _cinematicCurve = Cubic(0.22, 0.0, 0.15, 1.0);

  final FractalController controller;
  final AutoExploreConfig config;
  late final AutoExploreZoomPlanner _zoomPlanner = AutoExploreZoomPlanner(
    config: config,
  );

  bool _isExploring = false;
  bool _isPaused = false;
  bool _pausedByUserCorrection = false;
  bool _isUserInteracting = false;
  double _speed = 1.0;

  Timer? _timer;
  Timer? _anim;

  double? _cycleBaseZoom;
  double? _lastCorrectionZoom;
  double? _interactionStartZoom;
  bool _zoomingIn = true;

  AutoExploreService({
    required this.controller,
    this.config = const AutoExploreConfig(),
  });

  bool get isExploring => _isExploring;
  bool get isPaused => _isPaused;

  /// True while user interaction temporarily takes control.
  bool get pausedByUserCorrection => _pausedByUserCorrection;

  double get speed => _speed;
  set speed(double v) {
    _speed = AutoExploreSpeed.normalize(v);
    notifyListeners();
  }

  void start() {
    if (_isExploring && !_isPaused) return;

    _isExploring = true;
    _isPaused = false;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _adoptCurrentZoomAsCycleBase();
    _zoomingIn = true;

    _scheduleNext();
    notifyListeners();
  }

  void pause() {
    if (!_isExploring) return;

    _isPaused = true;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _timer?.cancel();
    _anim?.cancel();
    notifyListeners();
  }

  void resume() {
    if (!_isExploring) {
      start();
      return;
    }

    _isPaused = false;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _adoptCurrentZoomAsCycleBase();
    _scheduleNext();
    notifyListeners();
  }

  /// Called when user starts a continuous gesture (drag/pinch).
  ///
  /// Auto movement is temporarily suspended so manual pan/zoom is never fought.
  void onUserInteractionStart() {
    if (!_isExploring || _isPaused) return;
    if (_isUserInteracting) return;

    _isUserInteracting = true;
    _pausedByUserCorrection = true;
    _interactionStartZoom = _clampZoom(controller.view.zoom);

    _timer?.cancel();
    _anim?.cancel();
    notifyListeners();
  }

  /// Called when user ends a continuous gesture.
  ///
  /// The user-selected zoom becomes the new baseline and auto mode continues.
  void onUserInteractionEnd() {
    if (!_runtimeState.canAdoptContinuousInteractionEnd) return;

    final referenceZoom = _interactionStartZoom;
    _isUserInteracting = false;
    _interactionStartZoom = null;

    _adoptUserViewAndContinue(referenceZoom: referenceZoom);
  }

  /// Called for one-shot user corrections (mouse wheel, keyboard, etc).
  void onUserCorrection() {
    if (!AutoExploreUserCorrectionPolicy.shouldAdoptOneShotCorrection(
      _runtimeState,
    )) {
      return;
    }
    _adoptUserViewAndContinue();
  }

  void _adoptUserViewAndContinue({double? referenceZoom}) {
    if (!_isExploring) return;

    final adoption = _adoptedZoom(referenceZoom: referenceZoom);
    _zoomingIn = adoption.zoomingIn;

    _cycleBaseZoom = adoption.currentZoom;
    _lastCorrectionZoom = adoption.currentZoom;
    _pausedByUserCorrection = false;

    // Restart leg planning from the user-selected zoom immediately.
    _timer?.cancel();
    _anim?.cancel();
    if (!_isPaused && !_isUserInteracting) {
      _scheduleNext();
    }

    notifyListeners();
  }

  void toggle() {
    if (!_isExploring) return start();
    if (_isPaused) return resume();
    return pause();
  }

  void stop() {
    _isExploring = false;
    _isPaused = false;
    _pausedByUserCorrection = false;
    _isUserInteracting = false;
    _interactionStartZoom = null;
    _timer?.cancel();
    _anim?.cancel();
    _cycleBaseZoom = null;
    _lastCorrectionZoom = null;
    _zoomingIn = true;
    notifyListeners();
  }

  double _clampZoom(double z) => _zoomPlanner.clampZoom(z);

  AutoExploreRuntimeState get _runtimeState => AutoExploreRuntimeState(
        isExploring: _isExploring,
        isPaused: _isPaused,
        isUserInteracting: _isUserInteracting,
        pausedByUserCorrection: _pausedByUserCorrection,
      );

  AutoExploreZoomAdoption _adoptedZoom({double? referenceZoom}) {
    return AutoExploreZoomAdoption.fromSamples(
      bounds: AutoExploreZoomBounds.fromConfig(config),
      currentZoom: controller.view.zoom,
      referenceZoom: referenceZoom,
      lastCorrectionZoom: _lastCorrectionZoom,
      wasZoomingIn: _zoomingIn,
    );
  }

  void _adoptCurrentZoomAsCycleBase() {
    final currentZoom = _clampZoom(controller.view.zoom);
    _cycleBaseZoom = currentZoom;
    _lastCorrectionZoom = currentZoom;
  }

  double _nextTargetZoom() {
    final current = _clampZoom(controller.view.zoom);
    _cycleBaseZoom ??= current;

    // Direction is flipped only after a leg actually reaches its target.
    // This prevents user pan interruptions from resuming in the opposite
    // direction (the reported "reverse" behavior).
    return _zoomPlanner.nextTargetZoom(
      currentZoom: current,
      cycleBaseZoom: _cycleBaseZoom,
      zoomingIn: _zoomingIn,
      moduleId: controller.module.id,
    );
  }

  void _scheduleNext() {
    _timer?.cancel();
    if (!_runtimeState.canScheduleZoomLeg) return;

    // Continuous mode: no dwell/pause between zoom-in and zoom-out legs.
    _timer = Timer(Duration.zero, () async {
      if (!_runtimeState.canScheduleZoomLeg) return;

      final targetZoom = _nextTargetZoom();
      final reachedTarget = await _animateZoomTo(targetZoom);

      if (!_runtimeState.canScheduleZoomLeg) return;
      if (reachedTarget) {
        _zoomingIn = !_zoomingIn;
      }
      _scheduleNext();
    });
  }

  Future<bool> _animateZoomTo(double targetZoom) async {
    _anim?.cancel();

    final plan = _zoomPlanner.animationPlanForZoomLeg(
      startZoom: controller.view.zoom,
      endZoom: targetZoom,
      speed: _speed,
    );
    var step = 0;

    final completer = Completer<bool>();
    _anim = Timer.periodic(plan.frameInterval, (timer) {
      if (_runtimeState.shouldInterruptAnimation) {
        timer.cancel();
        _anim = null;
        if (!completer.isCompleted) completer.complete(false);
        return;
      }

      step++;
      final progress = plan.progressForFrame(step);
      final eased = _cinematicCurve.transform(progress.raw);

      controller.updateZoom(plan.interpolate(eased));
      _lastCorrectionZoom = _clampZoom(controller.view.zoom);

      if (progress.reachedEnd) {
        timer.cancel();
        _anim = null;
        if (!completer.isCompleted) completer.complete(true);
      }
    });

    return completer.future;
  }

  @override
  void dispose() {
    stop();
    super.dispose();
  }
}

/// Pure playback-state contract for [AutoExploreService].
///
/// The service owns timers and controller side effects, but scheduling decisions
/// depend only on these flags. Keeping that contract replayable makes hidden
/// state-order assumptions testable without a wall-clock timer.
class AutoExploreRuntimeState {
  final bool isExploring;
  final bool isPaused;
  final bool isUserInteracting;
  final bool pausedByUserCorrection;

  const AutoExploreRuntimeState({
    required this.isExploring,
    required this.isPaused,
    required this.isUserInteracting,
    required this.pausedByUserCorrection,
  }) : assert(
          !pausedByUserCorrection || (isExploring && !isPaused),
          'pausedByUserCorrection is only valid while auto-explore is armed',
        );

  /// A new auto-zoom leg can start only when auto-explore owns motion.
  ///
  /// Treat [pausedByUserCorrection] as its own motion blocker instead of
  /// relying on [isUserInteracting] to also be true. That keeps release builds
  /// safe if timer callbacks observe a transient flag-order mismatch.
  bool get canScheduleZoomLeg =>
      isExploring && !isPaused && !isUserInteracting && !pausedByUserCorrection;

  /// A continuous gesture end can adopt the user-selected view only if a
  /// matching gesture start currently owns motion.
  bool get canAdoptContinuousInteractionEnd =>
      isExploring && !isPaused && isUserInteracting;

  /// An in-flight animation must stop as soon as auto-explore loses motion.
  bool get shouldInterruptAnimation => !canScheduleZoomLeg;
}

/// Pure gate for one-shot user corrections such as mouse-wheel zooms.
///
/// Continuous gestures are already represented by [isUserInteracting] and use
/// [AutoExploreService.onUserInteractionEnd] to adopt the final zoom once. A
/// wheel/keyboard correction delivered during that gesture must not clear the
/// temporary user-correction pause early.
class AutoExploreUserCorrectionPolicy {
  const AutoExploreUserCorrectionPolicy._();

  static bool shouldAdoptOneShotCorrection(AutoExploreRuntimeState state) {
    return state.isExploring && !state.isPaused && !state.isUserInteracting;
  }
}

import 'package:flutter_fractals/features/auto_explore/auto_explore_zoom_planner.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreCorrectionDecision', () {
    test('maps visible zoom changes to the next leg direction', () {
      expect(
        AutoExploreCorrectionDecision.fromZooms(
          currentZoom: 10.002,
          previousZoom: 10.0,
        ).resolve(currentZoomingIn: false),
        isTrue,
      );
      expect(
        AutoExploreCorrectionDecision.fromZooms(
          currentZoom: 9.998,
          previousZoom: 10.0,
        ).resolve(currentZoomingIn: true),
        isFalse,
      );
    });

    test('preserves current direction inside the correction deadband', () {
      final decision = AutoExploreCorrectionDecision.fromZooms(
        currentZoom: 10.0005,
        previousZoom: 10.0,
      );

      expect(decision.changedDirection, isFalse);
      expect(decision.resolve(currentZoomingIn: true), isTrue);
      expect(decision.resolve(currentZoomingIn: false), isFalse);
    });

    test('normalizes malformed correction epsilon', () {
      final decision = AutoExploreCorrectionDecision.fromZooms(
        currentZoom: 10.0005,
        previousZoom: 10.0,
        relativeEpsilon: double.nan,
      );

      expect(decision.changedDirection, isFalse);
      expect(AutoExploreRelativeEpsilon.normalize(-0.1), 1e-4);
      expect(AutoExploreRelativeEpsilon.normalize(double.infinity), 1e-4);
    });

    test('normalizes correction epsilon before it hides zoom-out intent', () {
      final decision = AutoExploreCorrectionDecision.fromZooms(
        currentZoom: 5.0,
        previousZoom: 10.0,
        relativeEpsilon: 1.5,
      );

      expect(AutoExploreRelativeEpsilon.normalize(1.5), 1e-4);
      expect(decision.changedDirection, isTrue);
      expect(decision.resolve(currentZoomingIn: true), isFalse);
    });

    test('preserves direction when correction zoom samples are unusable', () {
      for (final sample in [
        (currentZoom: double.nan, previousZoom: 10.0),
        (currentZoom: double.infinity, previousZoom: 10.0),
        (currentZoom: 10.0, previousZoom: double.nan),
        (currentZoom: 10.0, previousZoom: double.infinity),
        (currentZoom: 10.0, previousZoom: 0.0),
      ]) {
        final decision = AutoExploreCorrectionDecision.fromZooms(
          currentZoom: sample.currentZoom,
          previousZoom: sample.previousZoom,
        );

        expect(
          decision.changedDirection,
          isFalse,
          reason:
              'current=${sample.currentZoom}, previous=${sample.previousZoom}',
        );
        expect(decision.resolve(currentZoomingIn: true), isTrue);
        expect(decision.resolve(currentZoomingIn: false), isFalse);
      }
    });

    test('replays user zoom adoption fallback order', () {
      const bounds = AutoExploreZoomBounds(minZoom: 0.2, maxZoom: 100.0);

      final interactionAdoption = AutoExploreZoomAdoption.fromSamples(
        bounds: bounds,
        currentZoom: 20.0,
        referenceZoom: 30.0,
        lastCorrectionZoom: 10.0,
        wasZoomingIn: true,
      );
      final correctionAdoption = AutoExploreZoomAdoption.fromSamples(
        bounds: bounds,
        currentZoom: 8.0,
        referenceZoom: null,
        lastCorrectionZoom: 10.0,
        wasZoomingIn: true,
      );
      final noHistoryAdoption = AutoExploreZoomAdoption.fromSamples(
        bounds: bounds,
        currentZoom: double.nan,
        referenceZoom: null,
        lastCorrectionZoom: null,
        wasZoomingIn: false,
      );

      expect(interactionAdoption.previousZoom, 30.0);
      expect(interactionAdoption.zoomingIn, isFalse);
      expect(correctionAdoption.previousZoom, 10.0);
      expect(correctionAdoption.zoomingIn, isFalse);
      expect(noHistoryAdoption.currentZoom, bounds.minZoom);
      expect(noHistoryAdoption.previousZoom, bounds.minZoom);
      expect(noHistoryAdoption.zoomingIn, isFalse);
      expect(noHistoryAdoption.correctionDecision.changedDirection, isFalse);
    });
  });

  group('AutoExploreZoomSpanScale', () {
    test('makes the cinematic duration span threshold explicit', () {
      expect(AutoExploreZoomSpanScale.normalized(double.nan), 0.0);
      expect(AutoExploreZoomSpanScale.normalized(-1.0), 0.0);
      expect(AutoExploreZoomSpanScale.normalized(0.8), 0.5);
      expect(AutoExploreZoomSpanScale.normalized(1.6), 1.0);
      expect(AutoExploreZoomSpanScale.normalized(3.2), 1.0);
    });
  });

  group('AutoExploreZoomPlanner', () {
    const planner = AutoExploreZoomPlanner(config: AutoExploreConfig());

    test('keeps peak zoom under module precision headroom', () {
      // Unknown modules use the default 1e7 precision threshold, so headroom is
      // 9.2e6. A base zoom near that edge used to let the 1.25x minimum peak
      // overrun the module-aware hard max.
      const moduleId = 'unknown_orbit_module';
      const baseZoom = 9.0e6;

      final hardMax = planner.hardMaxZoomFor(moduleId);
      final peakZoom = planner.computePeakZoom(
        baseZoom: baseZoom,
        moduleId: moduleId,
      );

      final candidates = planner.peakZoomCandidates(
        baseZoom: baseZoom,
        moduleId: moduleId,
      );

      expect(hardMax, 9.2e6);
      expect(candidates.precisionCappedDesiredZoom, hardMax);
      expect(candidates.precisionLimited, isTrue);
      expect(peakZoom, hardMax);
      expect(peakZoom, lessThanOrEqualTo(hardMax));
    });

    test('does not promote invalid precision headroom to max zoom', () {
      const planner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(precisionHeadroom: double.nan),
      );

      expect(planner.hardMaxZoomFor('unknown_orbit_module'), 1e7);
      expect(
        planner.computePeakZoom(
          baseZoom: 9.0e6,
          moduleId: 'unknown_orbit_module',
        ),
        lessThanOrEqualTo(1e7),
      );
    });

    test('plans zoom-in and zoom-out targets from the same cycle base', () {
      const baseZoom = 10.0;

      final zoomInPlan = planner.planNextTarget(
        currentZoom: 12.0,
        cycleBaseZoom: baseZoom,
        zoomingIn: true,
        moduleId: 'mandelbrot',
      );
      final zoomOutPlan = planner.planNextTarget(
        currentZoom: 12.0,
        cycleBaseZoom: baseZoom,
        zoomingIn: false,
        moduleId: 'mandelbrot',
      );

      expect(zoomInPlan.currentZoom, 12.0);
      expect(zoomInPlan.baseZoom, baseZoom);
      expect(zoomInPlan.peakZoom, 1200.0);
      expect(zoomInPlan.floorZoom, AutoExploreConfig().minZoom);
      expect(zoomInPlan.targetZoom, 1200.0);
      expect(zoomOutPlan.targetZoom, AutoExploreConfig().minZoom);
      expect(
        planner.nextTargetZoom(
          currentZoom: 12.0,
          cycleBaseZoom: baseZoom,
          zoomingIn: true,
          moduleId: 'mandelbrot',
        ),
        zoomInPlan.targetZoom,
      );
    });

    test('exposes sanitized target planning inputs', () {
      final missingBaseInputs = planner.planInputs(
        currentZoom: double.nan,
        cycleBaseZoom: null,
      );
      final malformedBaseInputs = planner.planInputs(
        currentZoom: 10.0,
        cycleBaseZoom: double.nan,
      );

      expect(missingBaseInputs.currentZoom, AutoExploreConfig().minZoom);
      expect(missingBaseInputs.baseZoom, missingBaseInputs.currentZoom);
      expect(malformedBaseInputs.currentZoom, 10.0);
      expect(malformedBaseInputs.baseZoom, AutoExploreConfig().minZoom);
    });

    test('makes collapsed target plans explicit', () {
      const collapsedPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: 1.0, maxZoom: 1.0),
      );

      final plan = collapsedPlanner.planNextTarget(
        currentZoom: 42.0,
        cycleBaseZoom: null,
        zoomingIn: true,
        moduleId: 'unknown_orbit_module',
      );

      expect(plan.currentZoom, 1.0);
      expect(plan.baseZoom, 1.0);
      expect(plan.peakZoom, 1.0);
      expect(plan.floorZoom, 1.0);
      expect(plan.isCollapsed, isTrue);
      expect(plan.targetRange.targetZoom(zoomingIn: false), 1.0);
      expect(plan.targetZoom, 1.0);
    });

    test('collapsed target plans do not return a base above resolved range',
        () {
      const precisionCollapsedPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: 1e11, maxZoom: 1e12),
      );

      final plan = precisionCollapsedPlanner.planNextTarget(
        currentZoom: 1e12,
        cycleBaseZoom: 1e12,
        zoomingIn: true,
        moduleId: 'unknown_orbit_module',
      );

      expect(plan.baseZoom, 1e12);
      expect(plan.peakZoom, 1e11);
      expect(plan.floorZoom, 1e11);
      expect(plan.isCollapsed, isTrue);
      expect(plan.targetZoom, 1e11);
      expect(
        precisionCollapsedPlanner.nextTargetZoom(
          currentZoom: 1e12,
          cycleBaseZoom: 1e12,
          zoomingIn: true,
          moduleId: 'unknown_orbit_module',
        ),
        1e11,
      );
    });

    test('orders target ranges after precision caps lower the peak', () {
      final plan = planner.planNextTarget(
        currentZoom: 1e12,
        cycleBaseZoom: 1e12,
        zoomingIn: false,
        moduleId: 'unknown_orbit_module',
      );
      final resolution = AutoExploreZoomTargetRangeResolution.fromCandidates(
        peakZoom: plan.peakCandidates.resolvedPeakZoom,
        floorZoom: planner.computeFloorZoom(plan.baseZoom),
      );

      expect(plan.peakZoom, 9.2e6);
      expect(plan.floorZoom, plan.peakZoom);
      expect(plan.isCollapsed, isTrue);
      expect(plan.targetZoom, 9.2e6);
      expect(plan.targetRange.floorZoom, lessThanOrEqualTo(plan.peakZoom));
      expect(
        resolution.requestedFloorZoom,
        moreOrLessEquals(
          1e12 / const AutoExploreConfig().cycleMaxMultiplier,
          epsilon: 1e-3,
        ),
      );
      expect(resolution.floorCappedByPeak, isTrue);
      expect(resolution.range.floorZoom, plan.peakZoom);
    });

    test('scales leg duration by zoom span and speed', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const fastPlanner = AutoExploreZoomPlanner(config: config);

      expect(
        fastPlanner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: 2.0,
        ),
        const Duration(milliseconds: 500),
      );
      expect(
        fastPlanner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1e6,
          speed: 2.0,
