import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';
import 'package:flutter_fractals/features/renderer/cpu_render_isolate.dart';
import 'package:flutter_fractals/features/renderer/cpu_viewport_mapping.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

void main() {
  group('CPU viewport mapping', () {
    test('subpixel samples stay inside the normalized viewport', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(
        viewport.normalizedSample(
          pixel: 0,
          extent: 2,
          sample: 0,
          samplesPerAxis: 1,
        ),
        closeTo(-0.5, 1e-12),
      );
      expect(
        viewport.normalizedSample(
          pixel: 1,
          extent: 2,
          sample: 0,
          samplesPerAxis: 1,
        ),
        closeTo(0.5, 1e-12),
      );
    });

    test('invalid subpixel sample candidates clamp to the pixel footprint', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(
        viewport.normalizedSample(
          pixel: 1,
          extent: 2,
          sample: 4,
          samplesPerAxis: 2,
        ),
        closeTo(0.75, 1e-12),
      );
      expect(
        viewport.normalizedSample(
          pixel: 0,
          extent: 2,
          sample: -1,
          samplesPerAxis: 2,
        ),
        closeTo(-0.75, 1e-12),
      );
    });

    test('edge pixels preserve iteration-buffer edge-inclusive contract', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(viewport.normalizedPixel(0, 2), -1.0);
      expect(viewport.normalizedPixel(1, 2), 1.0);
    });

    test('invalid zoom falls back to replayable unit-scale coordinates', () {
      for (final zoom in [
        double.nan,
        double.infinity,
        double.negativeInfinity,
      ]) {
        final viewport = CpuViewportMapping(
          viewPan: Vector2.zero(),
          viewZoom: zoom,
          width: 2,
          height: 2,
        );

        expect(viewport.scale, 1.5, reason: 'zoom=$zoom');
        expect(
          viewport.coordinate(nx: 0.5, ny: -0.5),
          (0.75, -0.75),
          reason: 'zoom=$zoom',
        );
      }
    });

    test('invalid viewport dimensions fall back to square aspect', () {
      expect(
        CpuViewportDimensions.fromSize(width: 0, height: 2).aspect,
        1.0,
      );
      expect(
        CpuViewportDimensions.fromSize(width: 2, height: -1).aspect,
        1.0,
      );

      final zeroWidthViewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 0,
        height: 2,
      );
      final negativeHeightViewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: -1,
      );

      expect(zeroWidthViewport.coordinate(nx: 0.5, ny: -0.5), (0.75, -0.75));
      expect(
        negativeHeightViewport.coordinate(nx: 0.5, ny: -0.5),
        (0.75, -0.75),
      );
    });

    test('isolate sample mapping shares invalid zoom normalization', () {
      final coordinate = cpuViewportCoordinateForSample(
        panX: 0.0,
        panY: 0.0,
        zoom: double.nan,
        fullWidth: 2,
        fullHeight: 2,
        x: 1,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(coordinate.x, 0.75);
      expect(coordinate.y, -0.75);
    });

    test('anti-aliasing grid makes non-square sample counts replayable', () {
      expect(CpuSampleGrid.fromRequestedCount(-1).samplesPerAxis, 1);
      expect(CpuSampleGrid.fromRequestedCount(1).totalSamples, 1);
      expect(CpuSampleGrid.fromRequestedCount(4).totalSamples, 4);
      expect(CpuSampleGrid.fromRequestedCount(8).samplesPerAxis, 3);
      expect(CpuSampleGrid.fromRequestedCount(8).totalSamples, 9);
    });

    test('anti-aliasing grid never drops requested multisample candidates', () {
      for (final requestedCount in [2, 3, 5, 6, 7, 8]) {
        final grid = CpuSampleGrid.fromRequestedCount(requestedCount);

        expect(
          grid.totalSamples,
          greaterThanOrEqualTo(requestedCount),
          reason: 'requestedCount=$requestedCount',
        );
        expect(grid.requestedCount, requestedCount);
        expect(grid.wasRoundedUp, isTrue);
      }
    });

    test('single-pixel iteration buffer samples the viewport center', () async {
      final buffer = await renderCpuIterationBuffer(
        moduleId: 'mandelbrot',
        viewPan: Vector2(-0.5, 0.0),
        viewZoom: 1.0,
        iterations: 50,
        bailout: 4.0,
        juliaC: Vector2(-0.8, 0.156),
        width: 1,
        height: 1,
      );

      expect(buffer, isNotNull);
      expect(buffer!.single, 50);
    });
  });
}

/// Safe parameter readers for uniform setters.
const double _maxSafeIntegerDouble = 9007199254740991.0;

bool _isSafeIntegerDouble(double value) {
  return value.isFinite && value.abs() <= _maxSafeIntegerDouble;
}

double readDouble(Map<String, Object> params, String key, double fallback) {
  final value = params[key];
  if (value is int) return value.toDouble();
  if (value is double && value.isFinite) return value;
  return fallback;
}

int readInt(Map<String, Object> params, String key, int fallback) {
  final value = params[key];
  if (value is int) return value;
  if (value is double && _isSafeIntegerDouble(value)) return value.round();
  return fallback;
}

import 'package:flutter_test/flutter_test.dart';

import 'package:flutter_fractals/core/modules/param_reader.dart';

void main() {
  group('readDouble', () {
    test('accepts finite int and double values', () {
      expect(readDouble({'power': 8}, 'power', 2.0), 8.0);
      expect(readDouble({'power': 3.5}, 'power', 2.0), 3.5);
    });

    test('falls back for missing, non-numeric, and non-finite values', () {
      expect(readDouble(const {}, 'power', 2.0), 2.0);
      expect(readDouble({'power': '8'}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.nan}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.infinity}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.negativeInfinity}, 'power', 2.0), 2.0);
    });
  });

  group('readInt', () {
    test('accepts integer values and rounds finite doubles', () {
      expect(readInt({'iterations': 120}, 'iterations', 80), 120);
      expect(readInt({'iterations': 120.4}, 'iterations', 80), 120);
      expect(readInt({'iterations': 120.5}, 'iterations', 80), 121);
    });

    test('falls back for missing, non-numeric, and non-finite values', () {
      expect(readInt(const {}, 'iterations', 80), 80);
      expect(readInt({'iterations': '120'}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.nan}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.infinity}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.negativeInfinity}, 'iterations', 80),
          80);
    });

    test('falls back for finite doubles outside integer range', () {
      expect(readInt({'iterations': 1e100}, 'iterations', 80), 80);
      expect(readInt({'iterations': -1e100}, 'iterations', 80), 80);
    });
  });
}

import 'dart:ui' as ui;

/// A strongly-typed uniform layout for FragmentProgram shaders.
///
/// Flutter's FragmentShader uniforms are set by *float index* and the indices
/// depend on the exact declaration order/types in the GLSL shader.
///
/// To avoid fragile hard-coded indices (which caused black output on device),
/// each fractal module should define a [UniformSchema] once and then set
/// uniforms by name.
class UniformSchema {
  UniformSchema._(this._entries, this.floatCount);

  final Map<String, UniformEntry> _entries;

  /// Total number of float slots consumed by all non-sampler uniforms.
  final int floatCount;

  UniformEntry operator [](String name) {
    final e = _entries[name];
    if (e == null) {
      throw ArgumentError('Unknown uniform: $name');
    }
    return e;
  }

  /// Creates a writer for a [ui.FragmentShader].
  UniformWriter writer(ui.FragmentShader shader) => UniformWriter._(this, shader);

  /// Builder.
  static UniformSchema build(void Function(UniformSchemaBuilder b) fn) {
    final b = UniformSchemaBuilder._();
    fn(b);
    return b._finish();
  }
}

sealed class UniformEntry {
  const UniformEntry(this.name, this.index);
  final String name;
  final int index;
  int get width;
}

class FloatEntry extends UniformEntry {
  const FloatEntry(super.name, super.index);
  @override
  int get width => 1;
}

class Vec2Entry extends UniformEntry {
  const Vec2Entry(super.name, super.index);
  @override
  int get width => 2;
}

class Vec3Entry extends UniformEntry {
  const Vec3Entry(super.name, super.index);
  @override
  int get width => 3;
}

class Vec4Entry extends UniformEntry {
  const Vec4Entry(super.name, super.index);
  @override
  int get width => 4;
}

class UniformSchemaBuilder {
  UniformSchemaBuilder._();

  final _entries = <String, UniformEntry>{};
  int _cursor = 0;

  void float(String name) => _add(FloatEntry(name, _cursor));
  void vec2(String name) => _add(Vec2Entry(name, _cursor));
  void vec3(String name) => _add(Vec3Entry(name, _cursor));
  void vec4(String name) => _add(Vec4Entry(name, _cursor));

  void _add(UniformEntry e) {
    if (_entries.containsKey(e.name)) {
      throw ArgumentError('Duplicate uniform: ${e.name}');
    }
    _entries[e.name] = e;
    _cursor += e.width;
  }

  UniformSchema _finish() => UniformSchema._(Map.unmodifiable(_entries), _cursor);
}

class UniformWriter {
  UniformWriter._(this.schema, this.shader);

  final UniformSchema schema;
  final ui.FragmentShader shader;

  void setFloat(String name, double v) {
    final e = schema[name];
    if (e is! FloatEntry) {
      throw ArgumentError('Uniform $name is not float (is ${e.runtimeType})');
    }
    shader.setFloat(e.index, v);
  }

  void setVec2(String name, double x, double y) {
    final e = schema[name];
    if (e is! Vec2Entry) {
      throw ArgumentError('Uniform $name is not vec2 (is ${e.runtimeType})');
    }
    shader.setFloat(e.index + 0, x);
    shader.setFloat(e.index + 1, y);
  }

  void setVec3(String name, double x, double y, double z) {
    final e = schema[name];
    if (e is! Vec3Entry) {
      throw ArgumentError('Uniform $name is not vec3 (is ${e.runtimeType})');
    }
    shader.setFloat(e.index + 0, x);
    shader.setFloat(e.index + 1, y);
    shader.setFloat(e.index + 2, z);
  }

  void setVec4(String name, double x, double y, double z, double w) {
    final e = schema[name];
    if (e is! Vec4Entry) {
      throw ArgumentError('Uniform $name is not vec4 (is ${e.runtimeType})');
    }
    shader.setFloat(e.index + 0, x);
    shader.setFloat(e.index + 1, y);
    shader.setFloat(e.index + 2, z);
    shader.setFloat(e.index + 3, w);
  }
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';

/// Stable catalog entry used by the redesigned browser.
///
/// This is intentionally separate from [FractalModule] so we can scale the
/// catalog to many entries (e.g. PRD 200) while still mapping to currently
/// implemented render modules.
@immutable
class CatalogEntry {
  /// Stable ID for catalog persistence, analytics, and deep links.
  ///
  /// Must never change once published.
  final String catalogId;

  /// Backing runtime fractal module that can render this entry today.
  final FractalModule module;

  /// Display category used to group entries in the catalog UI.
  final String category;

  /// Optional search aliases used by catalog filtering.
  final List<String> aliases;

  const CatalogEntry({
    required this.catalogId,
    required this.module,
    required this.category,
    this.aliases = const [],
  });
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time/catalog.dart';
import 'package:flutter_fractals/core/modules/builders/raymarched_3d/catalog.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/catalog/catalog_entry.dart';

/// Catalog data source for the Explore screen.
///
/// Phase 1: derives entries from currently implemented modules while assigning
/// stable catalog IDs. This keeps IDs future-proof for PRD-200 ingest.
class CatalogRepository {
  final List<CatalogEntry> entries;

  const CatalogRepository({required this.entries});

  factory CatalogRepository.fromRegistry(ModuleRegistry registry) {
    final categoriesById = {
      for (final config in escapeTimeCatalog) config.id: config.category,
      for (final config in raymarched3DCatalog) config.id: config.category,
    };

    return CatalogRepository(
      entries: registry.modules
          .map(
            (module) => CatalogEntry(
              // Stable prefix to decouple future module refactors from IDs.
              catalogId: 'core.${module.id}',
              module: module,
              category: categoriesById[module.id] ??
                  (module.dimension == FractalDimension.threeD
                      ? '3D Fractals'
                      : 'Other'),
            ),
          )
          .toList(growable: false),
    );
  }

  CatalogEntry byCatalogId(String catalogId) {
    return entries.firstWhere((entry) => entry.catalogId == catalogId);
  }

  @visibleForTesting
  Set<String> allIds() => entries.map((e) => e.catalogId).toSet();
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/catalog/catalog_repository.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CatalogRepository', () {
    test('creates stable prefixed IDs from module registry', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(repo.entries, isNotEmpty);
      expect(repo.entries.length, registry.modules.length);
      expect(repo.entries.first.catalogId, startsWith('core.'));
      expect(repo.byCatalogId('core.mandelbrot').module.id, 'mandelbrot');
    });

    test('catalog IDs are unique', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(repo.allIds().length, repo.entries.length);
    });

    test('keeps intended 3D runtime modules for implemented 3D catalog ids', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(
        repo.byCatalogId('core.quaternion_julia_3d').module.dimension,
        FractalDimension.threeD,
      );
      expect(
        repo.byCatalogId('core.dual_quaternion_julia').module.dimension,
        FractalDimension.threeD,
      );
      expect(
        repo.byCatalogId('core.mandelbox_shape_inversion').module.dimension,
        FractalDimension.threeD,
      );
    });
  });
}

